import { IcheckAuthOpts, IgetVerifyOpts, IgetLoginOpts } from './types';

declare namespace PhoneServer {
    /**
     * PhoneNumberServer
     */
    export class PhoneNumberServer {
        /**
         * 校验身份信息
         * @param opts 传入的参数checkAuthOpts
         */
        checkAuthAvailable(opts: IcheckAuthOpts): void;

        /**
         * 校验接入方身份信息(一键登录)
         * @param opt
         */

        checkLoginAvailable(opts: IcheckAuthOpts): void;

        /**
         * 获取本机号码校验token
         * @returns {object}
         */
        getVerifyToken(opts: IgetVerifyOpts): void;

        /**
         * 获取一键登录token
         * @param opts
         * @returns
         */
        getLoginToken(opts: IgetLoginOpts): void;

        /**
         * 设置日志是否打印更多信息  调试时开启上线关闭
         * @param isEnable
         */
        setLoggerEnable(isEnable: boolean): void;

       /**
        * 获取sdk版本号
        * @returns {string}
        */
        getVersion(): string;

        /**
         * 检查当前网络环境
         * @returns {boolean}
         */
        getConnection(): string;

        /**
         * 是否上传日志埋点 默认上传
         * @param isEnable
         */
        setUploadEnable(isEnable: boolean): void

    }

    /**
     * PhoneNumberServer错误枚举
     */
    export enum Errors {
        /**
         * 未知异常
         */
        ERROR_UNKNOW = 600010,

        /**
         * 校验接入方身份信息失败
         */

        ERROR_CHECK_AUTH = 600025,

        /**
         * 环境检测错误
         * @type {number}
         */
        ERROR_CHECK_ENV =600008,

        /**
         * 获取token失败
         */

        ERROR_GET_TOKEN = 600011,

        /**
         * 运营商维护升级，该功能不可用
         */

        ERROR_UNAVAILABLE = 600013,

        /**
         * 运营商维护升级，该功能已达最大调用次数
         */

        ERROR_MAX_TIME = 600014,

        /**
         * 请求超时
         */

        ERROR_TIMEOUT = 600015,

        /**
         * 接入方身份信息校验失败
         */
        ERROR_AUTH_INVALID = 600025,

        /**
         * 接入方身份信息校验失败
         */
        ERROR_PARAM = 600028,

         /**
         * css属性不合规
         */

        ERROR_CSS_PROP = 600030,

         /**
         * 业务类型错误
         */
       ERROR_BIZ_TYPE = 600032,

       // 请求参数已失效
       ERROR_REQUEST_INVALID = 600034
    }

}


declare module 'jsencrypt';

/// <reference types="react-scripts" />
declare module '*.less' {
    const content: { [className: string]: string };
    export default content;
}


export = PhoneServer;
export as namespace PhoneServer;
